# TypeScript Deep Merge Utility

A production-ready, fully typed `deepMerge` function that recursively merges two objects, handling nested objects, arrays, and primitives correctly.

## Implementation

```typescript
type DeepPartial<T> = T extends object
  ? { [P in keyof T]?: DeepPartial<T[P]> }
  : T;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  return (
    typeof value === 'object' &&
    value !== null &&
    !Array.isArray(value) &&
    Object.getPrototypeOf(value) === Object.prototype
  );
}

export function deepMerge<T extends Record<string, unknown>>(
  target: T,
  source: DeepPartial<T>,
): T {
  const result = { ...target };

  for (const key of Object.keys(source) as (keyof T)[]) {
    const targetVal = result[key];
    const sourceVal = source[key as keyof typeof source];

    if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(
        targetVal as Record<string, unknown>,
        sourceVal as Record<string, unknown>,
      ) as T[keyof T];
    } else if (sourceVal !== undefined) {
      result[key] = sourceVal as T[keyof T];
    }
  }

  return result;
}
```

## Usage Example

```typescript
interface AppConfig {
  api: {
    baseUrl: string;
    timeout: number;
    retries: number;
  };
  features: {
    darkMode: boolean;
    analytics: boolean;
  };
}

const defaults: AppConfig = {
  api: { baseUrl: 'https://api.example.com', timeout: 5000, retries: 3 },
  features: { darkMode: false, analytics: true },
};

const overrides: DeepPartial<AppConfig> = {
  api: { timeout: 10000 },      // only override timeout
  features: { darkMode: true }, // only override darkMode
};

const config = deepMerge(defaults, overrides);
// Result:
// {
//   api: { baseUrl: 'https://api.example.com', timeout: 10000, retries: 3 },
//   features: { darkMode: true, analytics: true }
// }
```

## Design Notes

- **Arrays are replaced, not merged** — merging arrays element-by-element is almost never the right semantic. If you need array merging, handle it explicitly at the call site.
- `isPlainObject` guards against merging class instances, `Date` objects, `RegExp`, and other non-plain objects that would break if spread.
- `DeepPartial<T>` ensures the source type is fully optional at every level, making it safe to pass partial override objects without TypeScript complaining about missing keys.
